function check_implementationCannotBeInitialized(address attacker, uint256 requiredValidators) public {
    // Deploy implementation directly (not via proxy)
    SettlementSignatureVerifier impl = new SettlementSignatureVerifier();

    // Attacker attempts to call initialize directly on implementation
    vm.prank(attacker);
    try impl.initialize(attacker, requiredValidators) {
        // If initialize succeeds, the bug exists
        assert(false); // SHOULD FAIL on buggy code
    } catch {
        // Initialize should revert - this is correct behavior
        assert(true);
    }
}
